242	```ts
243	import { PluginError, type Plugin } from '@ax/core';
244	
245	const PLUGIN_NAME = '@ax/credentials-store-db';
246	const KEY_PREFIX_V2 = 'credential:v2:';
247	const KEY_PREFIX_V1 = 'credential:';
248	const REF_RE = /^[a-z0-9][a-z0-9_.-]{0,127}$/;
249	const OWNER_ID_RE = /^[A-Za-z0-9][A-Za-z0-9_.@-]{0,127}$/;
250	const SCOPE_VALUES = ['global', 'user', 'agent'] as const;
251	type Scope = (typeof SCOPE_VALUES)[number];
252	
253	export interface StoreBlobPutInput {
254	  scope: Scope;
255	  ownerId: string | null;
256	  ref: string;
257	  blob: Uint8Array;
258	}
259	export interface StoreBlobGetInput {
260	  scope: Scope;
261	  ownerId: string | null;
262	  ref: string;
263	}
264	export interface StoreBlobGetOutput {
265	  blob: Uint8Array | undefined;
266	}
267	export interface StoreBlobListInput {
268	  // null means "all scopes" (admin list); otherwise filter to one.
269	  scope?: Scope;
270	  ownerId?: string | null;
271	}
272	export interface StoreBlobListEntry {
273	  scope: Scope;
274	  ownerId: string | null;
275	  ref: string;
276	  blob: Uint8Array;
277	}
278	export interface StoreBlobListOutput {
279	  entries: StoreBlobListEntry[];
280	}
281	
282	export function v2StorageKey(scope: Scope, ownerId: string | null, ref: string): string {
283	  return `${KEY_PREFIX_V2}${scope}:${ownerId ?? '_'}:${ref}`;
284	}
285	
286	export function v1StorageKey(userId: string, ref: string): string {
287	  return `${KEY_PREFIX_V1}${userId}:${ref}`;
288	}
289	
290	function validateScope(scope: unknown): Scope {
291	  if (typeof scope !== 'string' || !(SCOPE_VALUES as readonly string[]).includes(scope)) {
292	    throw new PluginError({
293	      code: 'invalid-payload',
294	      plugin: PLUGIN_NAME,
295	      message: `scope must be one of ${SCOPE_VALUES.join('|')}`,
296	    });
297	  }
298	  return scope as Scope;
299	}
300	function validateOwnerId(scope: Scope, ownerId: unknown): string | null {
301	  if (scope === 'global') {
302	    if (ownerId !== null) {
303	      throw new PluginError({ code: 'invalid-payload', plugin: PLUGIN_NAME, message: "ownerId must be null when scope='global'" });
304	    }
305	    return null;
306	  }
307	  if (typeof ownerId !== 'string' || !OWNER_ID_RE.test(ownerId)) {
308	    throw new PluginError({ code: 'invalid-payload', plugin: PLUGIN_NAME, message: `ownerId must match ${OWNER_ID_RE.source}` });
309	  }
310	  return ownerId;
311	}
312	function validateRef(ref: unknown): string {
313	  if (typeof ref !== 'string' || !REF_RE.test(ref)) {
314	    throw new PluginError({ code: 'invalid-payload', plugin: PLUGIN_NAME, message: `ref must match ${REF_RE.source}` });
315	  }
316	  return ref;
317	}
318	
319	export function createCredentialsStoreDbPlugin(): Plugin {
320	  return {
321	    manifest: {
322	      name: PLUGIN_NAME,
323	      version: '0.0.0',
324	      registers: [
325	        'credentials:store-blob:put',
326	        'credentials:store-blob:get',
327	        'credentials:store-blob:list',
328	      ],
329	      calls: ['storage:get', 'storage:set', 'storage:list-prefix'],
330	      subscribes: [],
331	    },
332	    async init({ bus }) {
333	      bus.registerService<StoreBlobPutInput, void>(
334	        'credentials:store-blob:put',
335	        PLUGIN_NAME,
336	        async (ctx, input) => {
337	          const scope = validateScope(input.scope);
338	          const ownerId = validateOwnerId(scope, input.ownerId);
339	          const ref = validateRef(input.ref);
340	          if (!(input.blob instanceof Uint8Array)) {
341	            throw new PluginError({ code: 'invalid-payload', plugin: PLUGIN_NAME, message: 'blob must be Uint8Array' });
342	          }
343	          await bus.call('storage:set', ctx, { key: v2StorageKey(scope, ownerId, ref), value: input.blob });
344	        },
345	      );
346	
347	      bus.registerService<StoreBlobGetInput, StoreBlobGetOutput>(
348	        'credentials:store-blob:get',
349	        PLUGIN_NAME,
350	        async (ctx, input) => {
351	          const scope = validateScope(input.scope);
352	          const ownerId = validateOwnerId(scope, input.ownerId);
353	          const ref = validateRef(input.ref);
354	          const v2 = await bus.call<{ key: string }, { value: Uint8Array | undefined }>(
355	            'storage:get', ctx, { key: v2StorageKey(scope, ownerId, ref) });
356	          if (v2.value !== undefined) return { blob: v2.value };
357	          // Fallback to v1 ONLY for scope='user' (v1 keys were per-userId only).
358	          if (scope === 'user' && ownerId !== null) {
359	            const v1 = await bus.call<{ key: string }, { value: Uint8Array | undefined }>(
360	              'storage:get', ctx, { key: v1StorageKey(ownerId, ref) });
361	            return { blob: v1.value };
362	          }
363	          return { blob: undefined };
364	        },
365	      );
366	
367	      bus.registerService<StoreBlobListInput, StoreBlobListOutput>(
368	        'credentials:store-blob:list',
369	        PLUGIN_NAME,
370	        async (ctx, input) => {
371	          // Build prefix based on filters.
372	          let prefix = KEY_PREFIX_V2;
373	          if (input.scope !== undefined) {
374	            const scope = validateScope(input.scope);
375	            prefix += `${scope}:`;
376	            if (input.ownerId !== undefined) {
377	              const ownerId = validateOwnerId(scope, input.ownerId);
378	              prefix += `${ownerId ?? '_'}:`;
379	            }
380	          }
381	          const out = await bus.call<{ prefix: string }, { entries: Array<{ key: string; value: Uint8Array }> }>(
382	            'storage:list-prefix', ctx, { prefix });
383	          const entries: StoreBlobListEntry[] = [];
384	          for (const e of out.entries) {
385	            const rest = e.key.slice(KEY_PREFIX_V2.length); // "scope:owner:ref"
386	            const firstColon = rest.indexOf(':');
387	            const secondColon = rest.indexOf(':', firstColon + 1);
388	            if (firstColon < 0 || secondColon < 0) continue;
389	            const scope = rest.slice(0, firstColon) as Scope;
390	            const ownerRaw = rest.slice(firstColon + 1, secondColon);
391	            const ref = rest.slice(secondColon + 1);
392	            entries.push({
393	              scope,
394	              ownerId: ownerRaw === '_' ? null : ownerRaw,
395	              ref,
396	              blob: e.value,
397	            });
398	          }
399	          return { entries };
400	        },
401	      );
402	    },
403	  };
404	}
