688	```ts
689	async function doResolve(
690	  ctx: Parameters<Parameters<typeof bus.registerService>[2]>[0],
691	  userId: string,
692	  ref: string,
693	): Promise<string> {
694	  // Walk precedence: user → agent → global → envFallback → not-found.
695	  type Scope = 'user' | 'agent' | 'global';
696	  const attempts: Array<{ scope: Scope; ownerId: string | null }> = [];
697	  attempts.push({ scope: 'user', ownerId: userId });
698	  if (ctx.agentId !== undefined && ctx.agentId !== '') {
699	    attempts.push({ scope: 'agent', ownerId: ctx.agentId });
700	  }
701	  attempts.push({ scope: 'global', ownerId: null });
702	
703	  for (const a of attempts) {
704	    const got = await bus.call<
705	      { scope: Scope; ownerId: string | null; ref: string },
706	      { blob: Uint8Array | undefined }
707	    >('credentials:store-blob:get', ctx, { scope: a.scope, ownerId: a.ownerId, ref });
708	    if (got.blob === undefined) continue;
709	    const env = unwrapEnvelope(got.blob);
710	    if (env.isTombstone) continue; // tombstone in this scope; try next
711	    // Resolve via per-kind sub-service (existing logic).
712	    const subService = `credentials:resolve:${env.kind}`;
713	    if (bus.hasService(subService)) {
714	      const out = await bus.call<CredentialsResolveInput, CredentialsResolveOutput>(
715	        subService, ctx, { payload: env.payload, userId, ref });
716	      if (out.refreshed !== undefined) {
717	        const refreshArgs: CredentialsSetInput = {
718	          scope: a.scope,
719	          ownerId: a.ownerId,
720	          ref, kind: env.kind,
721	          payload: out.refreshed.payload,
722	        };
723	        if (out.refreshed.expiresAt !== undefined) refreshArgs.expiresAt = out.refreshed.expiresAt;
724	        const md = out.refreshed.metadata ?? env.metadata;
725	        if (md !== undefined) refreshArgs.metadata = md;
726	        await bus.call('credentials:set', ctx, refreshArgs);
727	      }
728	      return out.value;
729	    }
730	    if (env.kind === 'api-key') return new TextDecoder().decode(env.payload);
731	    throw new PluginError({
732	      code: 'unsupported-credential-kind', plugin: PLUGIN_NAME,
733	      message: `no resolver registered for credential kind '${env.kind}' (ref='${ref}')`,
734	    });
735	  }
736	  // None of the v2 scopes had it. Try envFallback.
737	  const envName = envFallback[ref];
738	  if (envName !== undefined) {
739	    const v = process.env[envName];
740	    if (typeof v === 'string' && v.length > 0) return v;
741	  }
742	  throw new PluginError({
743	    code: 'credential-not-found', plugin: PLUGIN_NAME,
744	    message: `no credential for ref='${ref}'`,
745	  });
746	}
