1429	// packages/credentials-admin-routes/src/admin-routes.ts
1430	import { isRejection, makeAgentContext, PluginError, type AgentContext, type HookBus } from '@ax/core';
1431	import { z } from 'zod';
1432	
1433	export const ADMIN_BODY_MAX_BYTES = 64 * 1024;
1434	const PLUGIN_NAME = '@ax/credentials-admin-routes';
1435	
1436	export interface RouteRequest {
1437	  readonly headers: Record<string, string>;
1438	  readonly body: Buffer;
1439	  readonly cookies: Record<string, string>;
1440	  readonly query: Record<string, string>;
1441	  readonly params: Record<string, string>;
1442	  signedCookie(name: string): string | null;
1443	}
1444	export interface RouteResponse {
1445	  status(n: number): RouteResponse;
1446	  json(v: unknown): void;
1447	  text(s: string): void;
1448	  end(): void;
1449	}
1450	
1451	const REF_RE = /^[a-z0-9][a-z0-9_.-]{0,127}$/;
1452	const KIND_RE = /^[a-z0-9][a-z0-9_-]{0,63}$/;
1453	const OWNER_ID_RE = /^[A-Za-z0-9][A-Za-z0-9_.@-]{0,127}$/;
1454	
1455	const createBodySchema = z.object({
1456	  scope: z.enum(['global', 'user', 'agent']),
1457	  ownerId: z.string().regex(OWNER_ID_RE).nullable(),
1458	  ref: z.string().regex(REF_RE),
1459	  kind: z.string().regex(KIND_RE),
1460	  payload: z.string().min(1),                  // base64
1461	  expiresAt: z.number().int().positive().optional(),
1462	  metadata: z.record(z.string(), z.unknown()).optional(),
1463	}).strict().superRefine((v, ctx) => {
1464	  if (v.scope === 'global' && v.ownerId !== null) ctx.addIssue({ code: z.ZodIssueCode.custom, message: "ownerId must be null when scope='global'", path: ['ownerId'] });
1465	  if ((v.scope === 'user' || v.scope === 'agent') && v.ownerId === null) ctx.addIssue({ code: z.ZodIssueCode.custom, message: `ownerId is required when scope='${v.scope}'`, path: ['ownerId'] });
1466	});
1467	
1468	async function requireAdmin(bus: HookBus, ctx: AgentContext, req: RouteRequest, res: RouteResponse): Promise<{ id: string; isAdmin: boolean } | null> {
1469	  try {
1470	    const result = await bus.call<{ req: RouteRequest }, { user: { id: string; isAdmin: boolean } }>('auth:require-user', ctx, { req });
1471	    if (!result.user.isAdmin) {
1472	      res.status(403).json({ error: 'forbidden' });
1473	      return null;
1474	    }
1475	    return result.user;
1476	  } catch (err) {
1477	    if (err instanceof PluginError || isRejection(err)) {
1478	      res.status(401).json({ error: 'unauthenticated' });
1479	      return null;
1480	    }
1481	    throw err;
1482	  }
1483	}
1484	
1485	function writeServiceError(res: RouteResponse, err: unknown): boolean {
1486	  if (err instanceof PluginError) {
1487	    if (err.code === 'forbidden') { res.status(403).json({ error: 'forbidden' }); return true; }
1488	    if (err.code === 'not-found' || err.code === 'credential-not-found') { res.status(404).json({ error: 'not-found' }); return true; }
1489	    if (err.code === 'invalid-payload') { res.status(400).json({ error: err.message }); return true; }
1490	  }
1491	  return false;
1492	}
1493	
1494	interface Deps { bus: HookBus }
1495	
1496	export function createAdminCredentialsHandlers(deps: Deps) {
1497	  const ctx = makeAgentContext({ sessionId: 'credentials-admin', agentId: PLUGIN_NAME, userId: 'admin' });
1498	  return {
1499	    async list(req: RouteRequest, res: RouteResponse): Promise<void> {
1500	      const actor = await requireAdmin(deps.bus, ctx, req, res);
1501	      if (!actor) return;
1502	      const out = await deps.bus.call<{}, { credentials: unknown[] }>('credentials:list', ctx, {});
1503	      res.status(200).json(out);
1504	    },
1505	
1506	    async create(req: RouteRequest, res: RouteResponse): Promise<void> {
1507	      const actor = await requireAdmin(deps.bus, ctx, req, res);
1508	      if (!actor) return;
1509	      if (req.body.length > ADMIN_BODY_MAX_BYTES) { res.status(413).json({ error: 'body-too-large' }); return; }
1510	      let raw: unknown;
1511	      try { raw = req.body.length === 0 ? {} : JSON.parse(req.body.toString('utf8')); } catch { res.status(400).json({ error: 'invalid-json' }); return; }
1512	      const parsed = createBodySchema.safeParse(raw);
1513	      if (!parsed.success) { res.status(400).json({ error: parsed.error.issues[0]?.message ?? 'invalid-payload' }); return; }
1514	      let payload: Uint8Array;
1515	      try { payload = new Uint8Array(Buffer.from(parsed.data.payload, 'base64')); } catch { res.status(400).json({ error: 'invalid-payload' }); return; }
1516	      try {
1517	        await deps.bus.call('credentials:set', ctx, {
1518	          scope: parsed.data.scope, ownerId: parsed.data.ownerId, ref: parsed.data.ref, kind: parsed.data.kind, payload,
1519	          ...(parsed.data.expiresAt !== undefined ? { expiresAt: parsed.data.expiresAt } : {}),
1520	          ...(parsed.data.metadata !== undefined ? { metadata: parsed.data.metadata } : {}),
1521	        });
1522	        // Echo metadata-only back.
1523	        res.status(201).json({ credential: {
1524	          scope: parsed.data.scope, ownerId: parsed.data.ownerId, ref: parsed.data.ref, kind: parsed.data.kind,
1525	          createdAt: new Date().toISOString(),
1526	          ...(parsed.data.expiresAt !== undefined ? { expiresAt: new Date(parsed.data.expiresAt).toISOString() } : {}),
1527	          ...(parsed.data.metadata !== undefined ? { metadata: parsed.data.metadata } : {}),
1528	        } });
1529	      } catch (err) { if (writeServiceError(res, err)) return; throw err; }
1530	    },
1531	
1532	    async destroy(req: RouteRequest, res: RouteResponse): Promise<void> {
1533	      const actor = await requireAdmin(deps.bus, ctx, req, res);
1534	      if (!actor) return;
1535	      const { scope, ownerId, ref } = req.params;
1536	      if (!scope || !ownerId || !ref) { res.status(400).json({ error: 'missing-params' }); return; }
1537	      const ownerIdResolved = ownerId === '_' ? null : ownerId;
1538	      try {
1539	        await deps.bus.call('credentials:delete', ctx, { scope: scope as 'global'|'user'|'agent', ownerId: ownerIdResolved, ref });
1540	        res.status(204).end();
1541	      } catch (err) { if (writeServiceError(res, err)) return; throw err; }
1542	    },
1543	  };
1544	}
1545	
1546	export async function registerAdminCredentialsRoutes(bus: HookBus, initCtx: AgentContext): Promise<Array<() => void>> {
1547	  const handlers = createAdminCredentialsHandlers({ bus });
1548	  const routes: Array<{ method: 'GET'|'POST'|'DELETE'; path: string; handler: (req: RouteRequest, res: RouteResponse) => Promise<void> }> = [
1549	    { method: 'GET', path: '/admin/credentials', handler: handlers.list },
1550	    { method: 'POST', path: '/admin/credentials', handler: handlers.create },
1551	    { method: 'DELETE', path: '/admin/credentials/:scope/:ownerId/:ref', handler: handlers.destroy },
1552	  ];
1553	  const unregisters: Array<() => void> = [];
1554	  for (const route of routes) {
1555	    const result = await bus.call<unknown, { unregister: () => void }>('http:register-route', initCtx, route);
1556	    unregisters.push(result.unregister);
1557	  }
1558	  return unregisters;
1559	}
