1873	import { randomBytes } from 'node:crypto';
1874	
1875	export interface PendingEntryInput {
1876	  codeVerifier: string;
1877	  state: string;
1878	  scope: 'global' | 'user' | 'agent';
1879	  ownerId: string | null;
1880	  ref: string;
1881	  kind: string;
1882	  userId: string;
1883	}
1884	export interface PendingEntry extends PendingEntryInput {
1885	  expiresAt: number;
1886	}
1887	
1888	export interface PendingStore {
1889	  stash(entry: PendingEntryInput): string;
1890	  claim(pendingId: string, expectedUserId: string): PendingEntry | undefined;
1891	}
1892	
1893	export function createPendingStore(opts: { ttlMs: number; capacity: number }): PendingStore {
1894	  const map = new Map<string, PendingEntry>();
1895	
1896	  function evictExpired(now: number) {
1897	    for (const [k, v] of map) if (v.expiresAt <= now) map.delete(k);
1898	  }
1899	  function evictOldestIfOverCapacity() {
1900	    while (map.size >= opts.capacity) {
1901	      let oldestKey: string | undefined;
1902	      let oldestExp = Infinity;
1903	      for (const [k, v] of map) if (v.expiresAt < oldestExp) { oldestExp = v.expiresAt; oldestKey = k; }
1904	      if (oldestKey === undefined) break;
1905	      map.delete(oldestKey);
1906	    }
1907	  }
1908	
1909	  return {
1910	    stash(entry) {
1911	      const now = Date.now();
1912	      evictExpired(now);
1913	      evictOldestIfOverCapacity();
1914	      const pendingId = randomBytes(32).toString('base64url');
1915	      map.set(pendingId, { ...entry, expiresAt: now + opts.ttlMs });
1916	      return pendingId;
1917	    },
1918	    claim(pendingId, expectedUserId) {
1919	      const now = Date.now();
1920	      evictExpired(now);
1921	      const entry = map.get(pendingId);
1922	      if (entry === undefined) return undefined;
1923	      // Always consume on lookup — even on userId mismatch, to avoid timing/behavior oracles.
1924	      map.delete(pendingId);
1925	      if (entry.userId !== expectedUserId) return undefined;
1926	      return entry;
1927	    },
1928	  };
1929	}
