1941	export function createCredentialsOauthPendingPlugin(opts: { ttlMs?: number; capacity?: number } = {}): Plugin {
1942	  const store = createPendingStore({ ttlMs: opts.ttlMs ?? 5 * 60 * 1000, capacity: opts.capacity ?? 1000 });
1943	  return {
1944	    manifest: {
1945	      name: PLUGIN_NAME,
1946	      version: '0.0.0',
1947	      // SINGLE-REPLICA ONLY: in-memory state means a different replica won't see
1948	      // the pending entry. Multi-replica deployments need either (a) sticky
1949	      // sessions for 5min, or (b) a DB-backed sibling plugin.
1950	      registers: ['credentials:oauth:stash-pending', 'credentials:oauth:claim-pending'],
1951	      calls: [],
1952	      subscribes: [],
1953	    },
1954	    async init({ bus }) {
1955	      bus.registerService<PendingEntryInput, { pendingId: string }>('credentials:oauth:stash-pending', PLUGIN_NAME, async (_ctx, input) => ({ pendingId: store.stash(input) }));
1956	      bus.registerService<{ pendingId: string; expectedUserId: string }, { entry: PendingEntryInput | undefined }>(
1957	        'credentials:oauth:claim-pending', PLUGIN_NAME,
1958	        async (_ctx, input) => {
1959	          if (typeof input.pendingId !== 'string' || typeof input.expectedUserId !== 'string') throw new PluginError({ code: 'invalid-payload', plugin: PLUGIN_NAME, message: 'pendingId and expectedUserId required' });
1960	          const entry = store.claim(input.pendingId, input.expectedUserId);
1961	          if (entry === undefined) return { entry: undefined };
1962	          // Strip expiresAt before returning — caller doesn't need it.
1963	          const { expiresAt: _e, ...rest } = entry;
1964	          return { entry: rest };
1965	        },
1966	      );
