2321	const writeHeaders = { 'content-type': 'application/json', 'x-requested-with': 'ax-admin' } as const;
2322	
2323	function b64(s: string): string {
2324	  // Browser: use btoa on UTF-8 bytes.
2325	  const enc = new TextEncoder().encode(s);
2326	  let bin = '';
2327	  for (const b of enc) bin += String.fromCharCode(b);
2328	  return btoa(bin);
2329	}
